import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface Cryptocurrency {
  name: string;
  symbol: string;
  currentPrice: number;
  change24h: number;
  changePercent24h: number;
}

interface WidgetData {
  cryptocurrency: Cryptocurrency;
  priceTrend24h: number[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const { cryptocurrency, priceTrend24h } = data;
  const isPositive = cryptocurrency.change24h >= 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2C2C2E' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#FFB300' }}>
              {cryptocurrency.name} ({cryptocurrency.symbol})
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: '#FFFFFF', mt: 0.5 }}>
              ${cryptocurrency.currentPrice.toLocaleString()}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isPositive ? (
                <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} />
              ) : (
                <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />
              )}
              <Typography variant="body2" sx={{ color: isPositive ? '#10B981' : '#EF4444' }}>
                ${Math.abs(cryptocurrency.change24h).toFixed(2)} ({cryptocurrency.changePercent24h.toFixed(2)}%)
              </Typography>
            </Stack>
          </Box>

          <LineChart
            height={80}
            series={[
              {
                data: priceTrend24h,
                color: '#1976D2',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: priceTrend24h.map((_, i) => i), hide: true }]}
            margin={{ top: 5, bottom: 5, left: 0, right: 0 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 1.5,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
